// Generate search queries based on brand catalog and target verticals
const searchQueries = [
  // Fragrance retailers
  '"premium fragrance" shop online -sephora -ulta -nordstrom -amazon -ebay',
  '"luxury perfume" retailer -sephora -ulta -nordstrom -amazon',
  '"niche fragrance" boutique online store',
  '"designer perfume" discount store online',

  // Specific brand searches
  '"Maison Francis Kurkdjian" buy online -sephora -nordstrom',
  '"Tom Ford" perfume shop -sephora -ulta -macys',
  '"Creed" fragrance retailer -nordstrom -neiman',
  '"Parfums de Marly" authorized retailer',

  // Cosmetics retailers
  '"luxury cosmetics" boutique online -sephora -ulta',
  '"premium beauty" retailer independent',
  '"Charlotte Tilbury" "La Mer" shop -nordstrom -sephora',

  // Discount/gray market signals
  '"authentic" "below retail" perfume shop',
  '"wholesale" premium fragrance retailer',
  '"discount" luxury perfume online store -amazon'
];

// If triggered by webhook with a custom query, use that instead
const webhookQuery = $('Webhook: Manual Discover')?.first()?.json?.query;
const queriesToRun = webhookQuery ? [webhookQuery] : searchQueries;

// Output each query as a separate item for batch processing
return queriesToRun.map(q => ({ json: { query: q } }));

// Extract retailer URLs from search results and deduplicate
const results = $input.all();
const excludeDomains = [
  'amazon.com', 'ebay.com', 'walmart.com', 'sephora.com', 'ulta.com',
  'nordstrom.com', 'macys.com', 'bloomingdales.com', 'neimanmarcus.com',
  'target.com', 'cvs.com', 'walgreens.com', 'wikipedia.org',
  'youtube.com', 'instagram.com', 'facebook.com', 'tiktok.com',
  'reddit.com', 'twitter.com', 'pinterest.com', 'yelp.com',
  'fragrantica.com', 'basenotes.com' // Review sites, not retailers
];

const urls = new Set();

for (const result of results) {
  const organicResults = result.json.organic_results || [];
  for (const r of organicResults) {
    try {
      const domain = new URL(r.link).hostname.replace('www.', '');
      if (!excludeDomains.some(d => domain.includes(d))) {
        urls.add(r.link);
      }
    } catch (e) {}
  }
}

return Array.from(urls).map(url => ({ json: { url } }));
